69:["$","details","Do I need DevOps knowledge to use CreateOS?",{"className":"bg-background-white border border-background-white rounded-xl group","children":[["$","summary",null,{"className":"px-6 py-4 cursor-pointer text-strong font-medium list-none flex items-center justify-between","children":[["$","span",null,{"children":"Do I need DevOps knowledge to use CreateOS?"}],["$","span",null,{"className":"text-soft group-open:rotate-180 transition-transform ml-4 shrink-0","children":"â–¾"}]]}],["$","p",null,{"className":"px-6 pb-4 text-soft text-sm leading-relaxed","children":"No. CreateOS abstracts all infrastructure complexity. SSL certificates are provisioned automatically via Let's Encrypt, CDN caching is enabled by default, load balancing and auto-scaling are built in, database provisioning is one click, and health checks run automatically. You focus on writing code â€” CreateOS handles containerization, orchestration, DNS, monitoring, and security scanning."}]]}]
6a:["$","details","How much does CreateOS cost?",{"className":"bg-background-white border border-background-white rounded-xl group","children":[["$","summary",null,{"className":"px-6 py-4 cursor-pointer text-strong font-medium list-none flex items-center justify-between","children":[["$","span",null,{"children":"How much does CreateOS cost?"}],["$","span",null,{"className":"text-soft group-open:rotate-180 transition-transform ml-4 shrink-0","children":"â–¾"}]]}],["$","p",null,{"className":"px-6 pb-4 text-soft text-sm leading-relaxed","children":"CreateOS offers four pricing tiers: Free ($0/month) includes 1 project, 30 build minutes, 1 custom domain, and 10 GB database storage with a 15-day trial. Plus ($49/month) includes 5 projects, 500 build minutes, 5 domains, 20 GB database, Kafka (10 topics), and Valkey cache (256 MB). Pro ($149/month) includes 20 projects, 2,000 build minutes, 20 domains, 100 GB database, Kafka (100 topics), Valkey (2 GB), marketplace publisher access, and unlimited security scans. Enterprise plans offer unlimited resources, dedicated infrastructure, and 24/7 support with custom pricing. Annual billing saves 20%."}]]}]
6b:["$","details","What databases does CreateOS support?",{"className":"bg-background-white border border-background-white rounded-xl group","children":[["$","summary",null,{"className":"px-6 py-4 cursor-pointer text-strong font-medium list-none flex items-center justify-between","children":[["$","span",null,{"children":"What databases does CreateOS support?"}],["$","span",null,{"className":"text-soft group-open:rotate-180 transition-transform ml-4 shrink-0","children":"â–¾"}]]}],["$","p",null,{"className":"px-6 pb-4 text-soft text-sm leading-relaxed","children":"CreateOS provides four managed infrastructure services provisioned with one click: PostgreSQL (ACID-compliant with full-text search, JSON support, extensions, and point-in-time recovery), MySQL 8.0+ (replication, connection pooling, JSON support), Apache Kafka (event streaming with exactly-once delivery, high throughput, and fault tolerance), and Valkey (Redis-compatible in-memory cache for sessions, rate limiting, pub/sub, and queues). Storage ranges from 10 GB (Free) to 100 GB (Pro), with dedicated instances available on Enterprise plans."}]]}]
6c:["$","details","What is the CreateOS template marketplace?",{"className":"bg-background-white border border-background-white rounded-xl group","children":[["$","summary",null,{"className":"px-6 py-4 cursor-pointer text-strong font-medium list-none flex items-center justify-between","children":[["$","span",null,{"children":"What is the CreateOS template marketplace?"}],["$","span",null,{"className":"text-soft group-open:rotate-180 transition-transform ml-4 shrink-0","children":"â–¾"}]]}],["$","p",null,{"className":"px-6 pb-4 text-soft text-sm leading-relaxed","children":"The CreateOS template marketplace is a curated collection of 150+ production-ready application templates across 13 categories: AI/ML, analytics, authentication, automation, marketing, blogs/CMS, security, observability, database, blockchain, computing, and more. Anyone can fork a template, customize it, and deploy in minutes. Template creators earn 70% revenue share on every deployment â€” making CreateOS a monetization platform for developers. Templates include SaaS starters with Stripe billing, AI chatbot scaffolds, blockchain DApps, admin dashboards, and more."}]]}]
6d:["$","details","How does AI-assisted building work on CreateOS?",{"className":"bg-background-white border border-background-white rounded-xl group","children":[["$","summary",null,{"className":"px-6 py-4 cursor-pointer text-strong font-medium list-none flex items-center justify-between","children":[["$","span",null,{"children":"How does AI-assisted building work on CreateOS?"}],["$","span",null,{"className":"text-soft group-open:rotate-180 transition-transform ml-4 shrink-0","children":"â–¾"}]]}],["$","p",null,{"className":"px-6 pb-4 text-soft text-sm leading-relaxed","children":"CreateOS includes a built-in AI code editor powered by NodeOpsGPT that guides the entire application lifecycle. Describe your application in plain English and the AI generates architecture, writes code, configures deployment, provisions databases, and deploys to production. CreateOS also integrates with external AI tools via Model Context Protocol (MCP) â€” meaning you can vibe code in Cursor, VS Code, or Claude Code and deploy directly to CreateOS without leaving your IDE."}]]}]
6e:["$","details","What is MCP integration and how does it work with CreateOS?",{"className":"bg-background-white border border-background-white rounded-xl group","children":[["$","summary",null,{"className":"px-6 py-4 cursor-pointer text-strong font-medium list-none flex items-center justify-between","children":[["$","span",null,{"children":"What is MCP integration and how does it work with CreateOS?"}],["$","span",null,{"className":"text-soft group-open:rotate-180 transition-transform ml-4 shrink-0","children":"â–¾"}]]}],["$","p",null,{"className":"px-6 pb-4 text-soft text-sm leading-relaxed","children":"Model Context Protocol (MCP) is an open standard that enables AI agents to discover and interact with external services. CreateOS supports MCP both as a deployment target (AI agents in Cursor, VS Code, and Claude Code can deploy to CreateOS) and as a hosting platform (you can deploy your own MCP servers on CreateOS). This enables AI-native workflows where code generation, deployment configuration, and going live happen entirely within the AI assistant's context â€” no manual steps required."}]]}]
